  variable: "--font-fraunces",
  subsets: ["latin"],
  display: "swap",
  axes: ["opsz", "SOFT", "WONK"],
});

export const metadata: Metadata = {
  title: "Lumière Dental — Premier Cosmetic & Family Dentistry",
  description:
    "Lumière Dental is an award-winning dental clinic offering cosmetic dentistry, dental implants, orthodontics, teeth whitening, and gentle family care. Book your appointment today.",
  keywords: [
    "dental clinic",
    "cosmetic dentistry",
    "teeth whitening",
    "dental implants",
    "orthodontics",
    "family dentist",
    "invisible aligners",
    "emergency dentist",
  ],
  authors: [{ name: "Lumière Dental" }],
  openGraph: {
    title: "Lumière Dental — Premier Cosmetic & Family Dentistry",
    description:
      "Award-winning dental care. Cosmetic dentistry, implants, orthodontics & gentle family care.",
    siteName: "Lumière Dental",
    type: "website",
  },
  twitter: {
    card: "summary_large_image",
    title: "Lumière Dental",
    description: "Award-winning cosmetic & family dentistry.",
  },
};

export default function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <html lang="en" suppressHydrationWarning>
      <body
        className={`${geistSans.variable} ${fraunces.variable} antialiased bg-background text-foreground`}
      >
        <ThemeProvider
          attribute="class"
          defaultTheme="light"
          enableSystem
          disableTransitionOnChange
        >
          {children}
          <Toaster />
          <SonnerToaster richColors position="top-right" />
        </ThemeProvider>
      </body>
    </html>
  );
}

@import "tailwindcss";
@import "tw-animate-css";

@custom-variant dark (&:is(.dark *));

@theme inline {
  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --font-sans: var(--font-geist-sans);
  --font-mono: var(--font-geist-mono);
  --font-display: var(--font-fraunces);
  --color-sidebar-ring: var(--sidebar-ring);
  --color-sidebar-border: var(--sidebar-border);
  --color-sidebar-accent-foreground: var(--sidebar-accent-foreground);
  --color-sidebar-accent: var(--sidebar-accent);
  --color-sidebar-primary-foreground: var(--sidebar-primary-foreground);
  --color-sidebar-primary: var(--sidebar-primary);
  --color-sidebar-foreground: var(--sidebar-foreground);
  --color-sidebar: var(--sidebar);
  --color-chart-5: var(--chart-5);
  --color-chart-4: var(--chart-4);
  --color-chart-3: var(--chart-3);
  --color-chart-2: var(--chart-2);
  --color-chart-1: var(--chart-1);
  --color-ring: var(--ring);
  --color-input: var(--input);
  --color-border: var(--border);
  --color-destructive: var(--destructive);
  --color-accent-foreground: var(--accent-foreground);
  --color-accent: var(--accent);
  --color-muted-foreground: var(--muted-foreground);
  --color-muted: var(--muted);
  --color-secondary-foreground: var(--secondary-foreground);
  --color-secondary: var(--secondary);
  --color-primary-foreground: var(--primary-foreground);
  --color-primary: var(--primary);
  --color-popover-foreground: var(--popover-foreground);
  --color-popover: var(--popover);
  --color-card-foreground: var(--card-foreground);
  --color-card: var(--card);
  --color-brand: var(--brand);
  --color-brand-foreground: var(--brand-foreground);
  --color-gold: var(--gold);
  --color-gold-foreground: var(--gold-foreground);
  --radius-sm: calc(var(--radius) - 4px);
  --radius-md: calc(var(--radius) - 2px);
  --radius-lg: var(--radius);
  --radius-xl: calc(var(--radius) + 4px);
  --radius-2xl: calc(var(--radius) + 10px);
}

:root {
  --radius: 0.75rem;
  /* Warm off-white background */
  --background: oklch(0.992 0.004 95);
  --foreground: oklch(0.22 0.02 165);
  --card: oklch(1 0 0);
  --card-foreground: oklch(0.22 0.02 165);
  --popover: oklch(1 0 0);
  --popover-foreground: oklch(0.22 0.02 165);
  /* Deep teal-emerald primary */
  --primary: oklch(0.52 0.1 172);
  --primary-foreground: oklch(0.99 0.005 95);
  --secondary: oklch(0.96 0.012 170);
  --secondary-foreground: oklch(0.3 0.04 172);
  --muted: oklch(0.965 0.008 170);
  --muted-foreground: oklch(0.5 0.02 170);
  --accent: oklch(0.95 0.02 170);
  --accent-foreground: oklch(0.3 0.05 172);
  --destructive: oklch(0.577 0.245 27.325);
  --border: oklch(0.91 0.012 170);
  --input: oklch(0.91 0.012 170);
  --ring: oklch(0.52 0.1 172);
  /* Brand teal for special accents */
  --brand: oklch(0.6 0.11 175);
  --brand-foreground: oklch(0.99 0.005 95);
  /* Warm gold accent for premium touches */
  --gold: oklch(0.78 0.135 80);
  --gold-foreground: oklch(0.25 0.03 80);
  --chart-1: oklch(0.52 0.1 172);
  --chart-2: oklch(0.7 0.12 175);
  --chart-3: oklch(0.78 0.135 80);
  --chart-4: oklch(0.65 0.08 160);
  --chart-5: oklch(0.55 0.06 180);
  --sidebar: oklch(0.985 0.005 95);
  --sidebar-foreground: oklch(0.22 0.02 165);
  --sidebar-primary: oklch(0.52 0.1 172);
  --sidebar-primary-foreground: oklch(0.99 0.005 95);
  --sidebar-accent: oklch(0.95 0.02 170);
  --sidebar-accent-foreground: oklch(0.3 0.05 172);
  --sidebar-border: oklch(0.91 0.012 170);
  --sidebar-ring: oklch(0.52 0.1 172);
}

.dark {
  --background: oklch(0.17 0.015 175);
  --foreground: oklch(0.97 0.005 95);
  --card: oklch(0.21 0.02 175);
  --card-foreground: oklch(0.97 0.005 95);
  --popover: oklch(0.21 0.02 175);
  --popover-foreground: oklch(0.97 0.005 95);
  --primary: oklch(0.72 0.1 175);
  --primary-foreground: oklch(0.17 0.02 175);
  --secondary: oklch(0.27 0.025 175);
  --secondary-foreground: oklch(0.97 0.005 95);
  --muted: oklch(0.25 0.02 175);
  --muted-foreground: oklch(0.72 0.015 170);
  --accent: oklch(0.3 0.04 175);
  --accent-foreground: oklch(0.97 0.005 95);
  --destructive: oklch(0.704 0.191 22.216);
  --border: oklch(1 0 0 / 12%);
  --input: oklch(1 0 0 / 15%);
  --ring: oklch(0.72 0.1 175);
  --brand: oklch(0.72 0.11 175);
  --brand-foreground: oklch(0.17 0.02 175);
  --gold: oklch(0.82 0.13 80);
  --gold-foreground: oklch(0.2 0.03 80);
  --chart-1: oklch(0.72 0.1 175);
  --chart-2: oklch(0.6 0.12 175);
  --chart-3: oklch(0.82 0.13 80);
  --chart-4: oklch(0.7 0.08 160);
  --chart-5: oklch(0.6 0.06 180);
  --sidebar: oklch(0.21 0.02 175);
  --sidebar-foreground: oklch(0.97 0.005 95);
  --sidebar-primary: oklch(0.72 0.1 175);
  --sidebar-primary-foreground: oklch(0.17 0.02 175);
  --sidebar-accent: oklch(0.3 0.04 175);
  --sidebar-accent-foreground: oklch(0.97 0.005 95);
  --sidebar-border: oklch(1 0 0 / 12%);
  --sidebar-ring: oklch(0.72 0.1 175);
}

@layer base {
  * {
    @apply border-border outline-ring/50;
  }
  body {
    @apply bg-background text-foreground;
    font-feature-settings: "ss01", "cv01";
  }
}

/* Custom utilities */
@layer utilities {
  .font-display {
    font-family: var(--font-fraunces), Georgia, serif;
    font-optical-sizing: auto;
  }
  .text-balance {
    text-wrap: balance;
  }
  .text-pretty {
    text-wrap: pretty;
  }
  /* Premium gradient text */
  .text-gradient-brand {
    background: linear-gradient(120deg, var(--primary), var(--brand));
    -webkit-background-clip: text;
    background-clip: text;
    -webkit-text-fill-color: transparent;
    color: transparent;
  }
  /* Glassmorphism */
  .glass {
    background: color-mix(in oklch, var(--card) 70%, transparent);
    backdrop-filter: blur(16px) saturate(140%);
    -webkit-backdrop-filter: blur(16px) saturate(140%);
  }
  .glass-strong {
    background: color-mix(in oklch, var(--card) 85%, transparent);
    backdrop-filter: blur(20px) saturate(160%);
    -webkit-backdrop-filter: blur(20px) saturate(160%);
  }
  /* Mesh gradient background */
  .mesh-bg {
    background-image:
      radial-gradient(at 18% 22%, color-mix(in oklch, var(--primary) 16%, transparent) 0px, transparent 50%),
      radial-gradient(at 82% 8%, color-mix(in oklch, var(--gold) 14%, transparent) 0px, transparent 50%),
      radial-gradient(at 75% 75%, color-mix(in oklch, var(--brand) 12%, transparent) 0px, transparent 50%),
      radial-gradient(at 25% 90%, color-mix(in oklch, var(--primary) 10%, transparent) 0px, transparent 50%);
  }
  /* Subtle grid pattern */
  .grid-pattern {
    background-image:
      linear-gradient(to right, color-mix(in oklch, var(--foreground) 4%, transparent) 1px, transparent 1px),
      linear-gradient(to bottom, color-mix(in oklch, var(--foreground) 4%, transparent) 1px, transparent 1px);
    background-size: 56px 56px;
  }
  /* Custom scrollbar */
  .scroll-elegant {
    scrollbar-width: thin;
    scrollbar-color: var(--primary) transparent;
  }
  .scroll-elegant::-webkit-scrollbar {
    width: 8px;
    height: 8px;
  }
  .scroll-elegant::-webkit-scrollbar-track {
    background: transparent;
  }
  .scroll-elegant::-webkit-scrollbar-thumb {
    background-color: color-mix(in oklch, var(--primary) 45%, transparent);
    border-radius: 9999px;
  }
  .scroll-elegant::-webkit-scrollbar-thumb:hover {
    background-color: var(--primary);
  }
  .shadow-glow {
    box-shadow: 0 0 0 1px color-mix(in oklch, var(--primary) 12%, transparent),
      0 18px 50px -12px color-mix(in oklch, var(--primary) 28%, transparent);
  }
  .shadow-soft {
    box-shadow: 0 1px 2px color-mix(in oklch, var(--foreground) 4%, transparent),
      0 10px 30px -12px color-mix(in oklch, var(--foreground) 10%, transparent);
  }
}

/* Marquee animation */
@keyframes marquee {
  from { transform: translateX(0); }
  to { transform: translateX(-50%); }
}
.animate-marquee {
  animation: marquee 32s linear infinite;
}

/* Soft float */
@keyframes float-soft {
  0%, 100% { transform: translateY(0); }
  50% { transform: translateY(-10px); }
}
.animate-float-soft {
  animation: float-soft 6s ease-in-out infinite;
}

/* Shimmer for skeletons */
@keyframes shimmer {
